import { Component, inject, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { AuthService } from '../../../core/services/auth.service';
import { GuestDataService } from '../../../core/services/guest-data.service';

@Component({
  selector: 'app-migration-success',
  standalone: true,
  imports: [CommonModule],
  template: `
    <div class="migration-success" *ngIf="showMessage">
      <div class="success-content">
        <div class="icon">✅</div>
        <div class="message">
          <h4>Welcome back!</h4>
          <p>Your previous analyses have been saved to your account.</p>
        </div>
        <button class="btn-close" (click)="dismiss()">×</button>
      </div>
    </div>
  `,
  styles: [`
    .migration-success {
      position: fixed;
      top: 80px;
      right: 20px;
      background: linear-gradient(135deg, #4CAF50 0%, #45a049 100%);
      color: white;
      border-radius: 12px;
      box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
      max-width: 350px;
      z-index: 1000;
      animation: slideIn 0.3s ease-out;
    }

    @keyframes slideIn {
      from {
        transform: translateX(100%);
        opacity: 0;
      }
      to {
        transform: translateX(0);
        opacity: 1;
      }
    }

    .success-content {
      padding: 20px;
      display: flex;
      align-items: flex-start;
      gap: 15px;
      position: relative;
    }

    .icon {
      font-size: 24px;
      flex-shrink: 0;
    }

    .message h4 {
      margin: 0 0 8px 0;
      font-size: 16px;
      font-weight: 600;
    }

    .message p {
      margin: 0;
      font-size: 14px;
      opacity: 0.9;
      line-height: 1.4;
    }

    .btn-close {
      position: absolute;
      top: 10px;
      right: 10px;
      background: none;
      border: none;
      color: white;
      font-size: 18px;
      cursor: pointer;
      opacity: 0.7;
      width: 24px;
      height: 24px;
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: 50%;
      transition: all 0.2s;
    }

    .btn-close:hover {
      opacity: 1;
      background: rgba(255, 255, 255, 0.1);
    }

    @media (max-width: 480px) {
      .migration-success {
        top: 70px;
        right: 10px;
        left: 10px;
        max-width: none;
      }
    }
  `]
})
export class MigrationSuccessComponent implements OnInit {
  private authService = inject(AuthService);
  private guestDataService = inject(GuestDataService);
  showMessage = false;

  ngOnInit(): void {
    // Show message if user just logged in and had guest data
    const justLoggedIn = sessionStorage.getItem('just-logged-in');
    const hadGuestData = sessionStorage.getItem('had-guest-data');
    
    if (justLoggedIn === 'true' && hadGuestData === 'true') {
      this.showMessage = true;
      // Clear the flags
      sessionStorage.removeItem('just-logged-in');
      sessionStorage.removeItem('had-guest-data');
      
      // Auto-dismiss after 5 seconds
      setTimeout(() => {
        this.showMessage = false;
      }, 5000);
    }
  }

  dismiss(): void {
    this.showMessage = false;
  }
}
